B.fC=new A.wt(0,"leistung")
B.b5V=new A.f4(B.fC,"stets zu unserer vollsten Zufriedenheit",'Sehr gut (Note 1). \u201evollsten" ist die h\xf6chste Steigerung.',1)
B.b5T=new A.f4(B.fC,"stets zu unserer vollen Zufriedenheit",'Gut (Note 2). \u201estets" + \u201evollen", aber nicht \u201evollsten".',2)
B.b5Y=new A.f4(B.fC,"zu unserer vollen Zufriedenheit",'Befriedigend (Note 3). Ohne \u201estets" \u2013 nur \u201evoll".',3)
B.b63=new A.f4(B.fC,"stets zu unserer Zufriedenheit",'Ausreichend (Note 4). \u201estets", aber ohne \u201evoll".',4)
B.b5U=new A.f4(B.fC,"zu unserer Zufriedenheit",'Mangelhaft (Note 5). Weder \u201estets" noch \u201evoll".',5)
B.b5X=new A.f4(B.fC,"hat sich bem\xfcht, den Anforderungen gerecht zu werden",'Ungen\xfcgend (Note 6). \u201ebem\xfcht" = die Anforderungen nicht erf\xfcllt.',6)
B.k_=new A.wt(1,"verhalten")
B.b60=new A.f4(B.k_,"Verhalten gegen\xfcber Vorgesetzten und Kollegen war stets vorbildlich",'Sehr gut. Reihenfolge Vorgesetzte \u2192 Kollegen und \u201estets vorbildlich".',1)
B.b62=new A.f4(B.k_,"Verhalten war stets einwandfrei / vorbildlich",'Gut. \u201estets einwandfrei" liegt unter \u201estets vorbildlich".',2)
B.b6_=new A.f4(B.k_,"Verhalten gab zu keiner Klage Anlass","Nur ausreichend \u2013 eine schwache Formulierung.",4)
B.b64=new A.f4(B.k_,"Verhalten gegen\xfcber Kollegen und Vorgesetzten (Kollegen zuerst)","Werden die Kollegen vor den Vorgesetzten genannt, deutet das auf ein gest\xf6rtes Verh\xe4ltnis zu den Vorgesetzten hin.",null)
B.ux=new A.wt(2,"schlussformel")
B.b5Z=new A.f4(B.ux,"Wir bedauern sein Ausscheiden, danken f\xfcr die stets gute Zusammenarbeit und w\xfcnschen f\xfcr die Zukunft alles Gute","Positive, vollst\xe4ndige Schlussformel \u2013 ein gutes Zeichen.",null)
B.b61=new A.f4(B.ux,"Fehlende Schlussformel (kein Dank, kein Bedauern, keine guten W\xfcnsche)","Das Fehlen der Schlussformel gilt als Distanzierung und wertet ein sonst gutes Zeugnis ab.",null)
B.o2=new A.wt(3,"code")
B.b5R=new A.f4(B.o2,"trug durch seine Geselligkeit zur Verbesserung des Betriebsklimas bei","Kann auf \xfcberm\xe4\xdfigen Alkoholkonsum anspielen.",null)
B.b5S=new A.f4(B.o2,"war stets bem\xfcht",'\u201ebem\xfcht" ohne Erfolg = die Leistung war nicht ausreichend.',null)
B.b5W=new A.f4(B.o2,"zeigte f\xfcr die Belange der Belegschaft (gro\xdfes) Verst\xe4ndnis","Kann andeuten, dass die Person mehr mit Betriebsrats-/Kollegen-Themen als mit der Arbeit besch\xe4ftigt war.",null)
